+
+const profileUpdateSchema = z.object({
+  fullName: z.string().min(1).optional(),
+  phone: z.string().optional(),
+  dob: z.string().optional(),
+  gender: z.enum(["MALE", "FEMALE", "OTHER"]).optional(),
+  addressLine: z.string().optional(),
+  ward: z.string().optional(),
+  district: z.string().optional(),
+  province: z.string().optional()
+});
+
+function toUserBasic(user: User) {
+  return {
+    id: user.id,
+    email: user.email,
+    phone: user.phone,
+    fullName: user.fullName,
+    status: user.status,
+    gender: user.gender,
+    dob: user.dob,
+    addressLine: user.addressLine,
+    ward: user.ward,
+    district: user.district,
+    province: user.province,
+    emailVerifiedAt: user.emailVerifiedAt,
+    lastLoginAt: user.lastLoginAt,
+    createdAt: user.createdAt,
+    updatedAt: user.updatedAt
+  };
+}
+
+function buildVerifyToken() {
+  const token = generateRandomToken(32);
+  return {
+    token,
+    tokenHash: hashToken(token),
+    expiresAt: addMinutes(env.VERIFY_TOKEN_EXPIRES_MINUTES)
+  };
+}
+
+function buildResetToken() {
+  const token = generateRandomToken(32);
+  return {
+    token,
+    tokenHash: hashToken(token),
+    expiresAt: addMinutes(env.RESET_TOKEN_EXPIRES_MINUTES)
+  };
+}
+
+function buildRefreshToken() {
+  const token = generateRandomToken(64);
+  return {
+    token,
+    tokenHash: hashToken(token),
+    expiresAt: addDuration(env.REFRESH_TOKEN_EXPIRES)
+  };
+}
+
+router.post("/auth/register", authLimiter, async (req, res) => {
+  const parsed = registerSchema.safeParse(req.body);
+  if (!parsed.success) {
+    return res.status(400).json({ message: "Invalid input", issues: parsed.error.issues });
+  }
+
+  const { email, password, fullName, phone } = parsed.data;
+
+  const existingByEmail = await prisma.user.findUnique({ where: { email } });
