+    }
+  });
+
+  const { token, tokenHash, expiresAt } = buildVerifyToken();
+  await prisma.emailVerification.upsert({
+    where: { userId: user.id },
+    update: { tokenHash, expiresAt, usedAt: null },
+    create: { userId: user.id, tokenHash, expiresAt }
